queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?ride_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasRides ?child ; p:hasAmusement_Parks ?parent . } GROUP BY ?child }
  ?child p:ride_name ?ride_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Amusement_Parks } }
  FILTER(?nf = ?total)
}

